#include<bits/stdc++.h>
using namespace std;
int a[100010],b[100010];
int n;
long long ans;
void mergesort(int l,int r)
{
    if(l>=r)
    {
        return;
    }
    int mid=(l+r)/2;
    mergesort(l,mid);
    mergesort(mid+1,r);
    int i=l,j=mid+1,tot=l;
    while(i<=mid&&j<=r)
    {
        if(a[i]<=a[j])
        {
            b[tot++]=a[i++];
        }
        else
        {
            b[tot++]=a[j++];
            ans+=mid-i+1;
        }
    }
    while(i<=mid)
    {
        b[tot++]=a[i++];
    }
    while(j<=r)
    {
        b[tot++]=a[j++];
    }
    for(int k=l;k<=r;k++)
    {
        a[k]=b[k];
    }
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    int lst=1;
    for(int i=2;i<=n;i++)
    {
        if(a[i]>=a[i-1])
        {
            reverse(a+lst,a+i);
            lst=i;
            ans++;
        }
    }
    ans++;
    reverse(a+lst,a+1+n);
    mergesort(1,n);
    printf("%lld",ans);
    return 0;
}
